import{_ as a,o,c as i,ag as l}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"حول Dotfiles (AR)","titleTemplate":":title","description":"الجيل التالي من إعدادات الشل. أداء عالٍ وآمن ومُحسّن للذكاء الاصطناعي. يُدار بواسطة Chezmoi. متوافق مع macOS وLinux وWSL عبر Dotfiles.","frontmatter":{"title":"حول Dotfiles","description":"الجيل التالي من إعدادات الشل. أداء عالٍ وآمن ومُحسّن للذكاء الاصطناعي. يُدار بواسطة Chezmoi. متوافق مع macOS وLinux وWSL عبر Dotfiles.","lang":"ar-SA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"حول Dotfiles preview","canonical":"/ar/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"حول Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"حول Dotfiles - Dotfiles (AR)","permalink":"/ar/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, إعدادات, أتمتة, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"الجيل التالي من إعدادات الشل. أداء عالٍ وآمن ومُحسّن للذكاء الاصطناعي. يُدار بواسطة Chezmoi."},{"name":"twitter:title","content":"حول Dotfiles"},{"name":"og:title","content":"حول Dotfiles"},{"name":"og:description","content":"الجيل التالي من إعدادات الشل. أداء عالٍ وآمن ومُحسّن للذكاء الاصطناعي. يُدار بواسطة Chezmoi."},{"name":"og:image:alt","content":"Dotfiles - مصمم ببساطة ليناسب حياتك مع الشل"},{"name":"og:locale","content":"ar_SA"}]},"headers":[],"relativePath":"ar/about/index.md","filePath":"ar/about/index.md","lastUpdated":1773010926000}'),t={name:"ar/about/index.md"};function s(d,e,n,c,r,h){return o(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="حول-dotfiles" tabindex="-1">حول Dotfiles <a class="header-anchor" href="#حول-dotfiles" aria-label="Permalink to &quot;حول Dotfiles&quot;">​</a></h1><p>المعيار الحديث لإعدادات الشل. مبني على <strong>Chezmoi</strong> لإدارة بيئة آمنة وعابرة للمنصات.</p><h2 id="اكتشف" tabindex="-1">اكتشف <a class="header-anchor" href="#اكتشف" aria-label="Permalink to &quot;اكتشف&quot;">​</a></h2><p>Dotfiles v0.2.495 يحوّل طرفيتك إلى مساحة عمل قوية وموحدة. على عكس ملفات dotfiles التقليدية التي تعتمد على Makefiles معقدة أو سكريبتات الروابط الرمزية، يستخدم Dotfiles نهجًا قائمًا على القوالب يتميز بالذرية والسرعة وقابلية إعادة الإنتاج.</p><h3 id="ما-الجديد" tabindex="-1">ما الجديد <a class="header-anchor" href="#ما-الجديد" aria-label="Permalink to &quot;ما الجديد&quot;">​</a></h3><ul><li><strong>نواة حديثة</strong> — بدائل Rust عالية الأداء تحل محل أدوات Unix التقليدية: <ul><li><strong>Atuin</strong> لسجل الشل</li><li><strong>Yazi</strong> لإدارة الملفات</li><li><strong>Zellij</strong> لتعدد الطرفيات</li><li><strong>Ghostty</strong> لطرفية مُسرّعة بـ GPU</li><li><strong>NeoVim</strong> للتحرير الحديث</li></ul></li><li><strong>أمان أصلي</strong> — توقيع SSH أصلي بالكامل بدون وكلاء خارجيين</li><li><strong>وضع تفاعلي</strong> — أمر <code>dot learn</code> الجديد يرشدك عبر الميزات</li></ul><h2 id="ابدأ" tabindex="-1">ابدأ <a class="header-anchor" href="#ابدأ" aria-label="Permalink to &quot;ابدأ&quot;">​</a></h2><h3 id="المتطلبات" tabindex="-1">المتطلبات <a class="header-anchor" href="#المتطلبات" aria-label="Permalink to &quot;المتطلبات&quot;">​</a></h3><ul><li><strong>macOS</strong> أو <strong>Linux (Ubuntu/Debian)</strong> أو <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> و<strong>Git</strong></li><li><strong>Chezmoi</strong> (يُثبّت تلقائيًا)</li><li><strong>Nerd Font</strong> (لأيقونات الطرفية)</li></ul><h3 id="التثبيت" tabindex="-1">التثبيت <a class="header-anchor" href="#التثبيت" aria-label="Permalink to &quot;التثبيت&quot;">​</a></h3><p>نفّذ أمرًا واحدًا لتثبيت المجموعة الكاملة:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>سيقوم المُثبّت بما يلي:</p><ol><li>تثبيت برنامج <code>chezmoi</code></li><li>استنساخ المستودع</li><li>تثبيت الحزم المطلوبة عبر Homebrew (macOS) أو Apt (Linux)</li><li>تطبيق إعداداتك</li></ol><h3 id="استكشف" tabindex="-1">استكشف <a class="header-anchor" href="#استكشف" aria-label="Permalink to &quot;استكشف&quot;">​</a></h3><p>بعد التثبيت، أعد تشغيل طرفيتك ونفّذ:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>هذا يُطلق جولة تفاعلية لبيئتك الجديدة.</p><h2 id="خصص" tabindex="-1">خصص <a class="header-anchor" href="#خصص" aria-label="Permalink to &quot;خصص&quot;">​</a></h2><p>إعداداتك موجودة في <code>~/.local/share/chezmoi</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # نقطة دخول الشل</span></span>
<span class="line"><span>├── dot_config/             # إعدادات XDG الأساسية (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # سجل الشل</span></span>
<span class="line"><span>│   ├── ghostty/            # محاكي الطرفية</span></span>
<span class="line"><span>│   ├── git/                # إعدادات Git</span></span>
<span class="line"><span>│   ├── yazi/               # مدير الملفات</span></span>
<span class="line"><span>│   ├── zellij/             # مضاعف الطرفية</span></span>
<span class="line"><span>│   ├── zsh/                # إعدادات Zsh</span></span>
<span class="line"><span>│   └── shell/              # الاختصارات والمسارات المشتركة</span></span>
<span class="line"><span>├── provision/              # سكريبتات دورة الحياة</span></span>
<span class="line"><span>├── install.sh              # المُثبّت العام</span></span>
<span class="line"><span>└── docs/                   # التوثيق</span></span></code></pre></div><h2 id="ساهم" tabindex="-1">ساهم <a class="header-anchor" href="#ساهم" aria-label="Permalink to &quot;ساهم&quot;">​</a></h2><p>انضم للمجتمع. راجع <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">مدونة السلوك</a> و<a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">إرشادات المساهمة</a>.</p><h2 id="الأوامر-الأساسية" tabindex="-1">الأوامر الأساسية <a class="header-anchor" href="#الأوامر-الأساسية" aria-label="Permalink to &quot;الأوامر الأساسية&quot;">​</a></h2><p>يوفر سطر أوامر <code>dot</code> ما يصل إلى 53 أمرًا منظمة حسب الفئة.</p><h3 id="الأساسية" tabindex="-1">الأساسية <a class="header-anchor" href="#الأساسية" aria-label="Permalink to &quot;الأساسية&quot;">​</a></h3><ul><li><code>dot apply</code> — يطبق تغييرات التكوين.</li><li><code>dot sync</code> — يجلب أحدث حالة للمستودع ويطبقها.</li><li><code>dot update</code> — يحدث المستودع ويسخن ذاكرة التخزين المؤقت.</li><li><code>dot add</code> — يضيف ملفات جديدة إلى مصدر Chezmoi.</li><li><code>dot diff</code> — يعرض التغييرات المعلقة قبل التطبيق.</li><li><code>dot status</code> — يعرض حالة الملفات المُدارة.</li><li><code>dot remove</code> — يلغي إدارة ملف ويحذف إدخال المصدر.</li><li><code>dot cd</code> — يفتح Shell في مجلد مصدر Chezmoi.</li><li><code>dot edit</code> — يفتح ملفًا مُدارًا في المحرر.</li><li><code>dot clean-cache</code> — يمسح ذاكرة التخزين المؤقت المؤقتة.</li><li><code>dot prewarm</code> — يملأ ذاكرة التخزين المؤقت مسبقًا لبدء Shell أسرع.</li></ul><h3 id="التشخيص" tabindex="-1">التشخيص <a class="header-anchor" href="#التشخيص" aria-label="Permalink to &quot;التشخيص&quot;">​</a></h3><ul><li><code>dot doctor</code> — يتحقق من المسارات والأدوات وحالة Shell.</li><li><code>dot heal</code> — يصلح الحالة المفقودة أو التالفة تلقائيًا.</li><li><code>dot health</code> — يشغل فحصًا صحيًا خفيفًا.</li><li><code>dot verify</code> — يتحقق من سلامة الملفات مقابل المصدر.</li><li><code>dot scorecard</code> — يطبع نتيجة جودة التكوين.</li><li><code>dot snapshot</code> — يلتقط الحالة الحالية للمقارنة لاحقًا.</li><li><code>dot smoke-test</code> — يتحقق من سلاسل الأدوات الأساسية بالكامل.</li><li><code>dot chaos</code> — يحقن أخطاء لاختبار الإصلاح الذاتي.</li><li><code>dot bundle</code> — يصدّر حزمة تكوين محمولة.</li><li><code>dot rollback</code> — يعود إلى لقطة سابقة.</li><li><code>dot drift</code> — يكتشف التغييرات غير المتوقعة على الملفات المُدارة.</li><li><code>dot history</code> — يعرض سجل تاريخ apply/sync.</li><li><code>dot benchmark</code> — يقيس وقت بدء Shell.</li><li><code>dot perf</code> — يحلل بطء تهيئة Shell.</li></ul><h3 id="المظهر" tabindex="-1">المظهر <a class="header-anchor" href="#المظهر" aria-label="Permalink to &quot;المظهر&quot;">​</a></h3><ul><li><code>dot theme</code> — يبدل نظام ألوان الطرفية.</li><li><code>dot wallpaper</code> — يعين خلفية سطح المكتب (macOS).</li><li><code>dot fonts</code> — يثبت أو يحدث Nerd Fonts.</li><li><code>dot tune</code> — يضبط كثافة الواجهة ونمط سطر الأوامر.</li></ul><h3 id="الأمان" tabindex="-1">الأمان <a class="header-anchor" href="#الأمان" aria-label="Permalink to &quot;الأمان&quot;">​</a></h3><ul><li><code>dot backup</code> — ينشئ نسخًا احتياطية مشفرة للتكوين.</li><li><code>dot encrypt-check</code> — يتحقق من تشفير المفاتيح السرية في حالة السكون.</li><li><code>dot firewall</code> — يُكوّن قواعد جدار الحماية.</li><li><code>dot telemetry</code> — يتحكم في بيانات الاستخدام المجهولة.</li><li><code>dot dns-doh</code> — يفعّل DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — يقفل الشاشة فورًا.</li><li><code>dot usb-safety</code> — يقيد التركيب التلقائي لتخزين USB.</li></ul><h3 id="المفاتيح-السرية" tabindex="-1">المفاتيح السرية <a class="header-anchor" href="#المفاتيح-السرية" aria-label="Permalink to &quot;المفاتيح السرية&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — يهيئ الواجهة الخلفية للمفاتيح السرية (age / GPG).</li><li><code>dot secrets</code> — يسرد إدخالات المفاتيح السرية المشفرة.</li><li><code>dot secrets-create</code> — ينشئ مفتاحًا سريًا مشفرًا جديدًا.</li><li><code>dot ssh-key</code> — يولد أو يدوّر أزواج مفاتيح SSH.</li><li><code>dot ssh-cert</code> — يطلب شهادة SSH من مرجع مصدق.</li></ul><h3 id="الذكاء-الاصطناعي" tabindex="-1">الذكاء الاصطناعي <a class="header-anchor" href="#الذكاء-الاصطناعي" aria-label="Permalink to &quot;الذكاء الاصطناعي&quot;">​</a></h3><ul><li><code>dot ai</code> — يفتح جلسة مساعد ذكاء اصطناعي تفاعلية.</li><li><code>dot ai-setup</code> — يُكوّن مفاتيح API لمزودي الذكاء الاصطناعي.</li><li><code>dot ai-query</code> — يرسل طلبًا واحدًا إلى نموذج ذكاء اصطناعي.</li><li>أغلفة أدوات الذكاء الاصطناعي: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="الأدوات" tabindex="-1">الأدوات <a class="header-anchor" href="#الأدوات" aria-label="Permalink to &quot;الأدوات&quot;">​</a></h3><ul><li><code>dot tools</code> — يسرد بدائل CLI المضمنة وحالتها.</li><li><code>dot new</code> — ينشئ ملف اختصار أو دالة جديد.</li><li><code>dot sandbox</code> — يفتح Shell رمل للاستخدام مرة واحدة.</li><li><code>dot keys</code> — يعرض اختصارات لوحة المفاتيح الحالية.</li><li><code>dot learn</code> — يبدأ البرنامج التعليمي التفاعلي.</li></ul><h3 id="معلومات-وصفية" tabindex="-1">معلومات وصفية <a class="header-anchor" href="#معلومات-وصفية" aria-label="Permalink to &quot;معلومات وصفية&quot;">​</a></h3><ul><li><code>dot upgrade</code> — يرقّي Dotfiles إلى أحدث إصدار.</li><li><code>dot packages</code> — يسرد الحزم المثبتة المُدارة بواسطة Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — يعرض معلومات الإصدار أو الاستخدام</li></ul>`,41)])])}const m=a(t,[["render",s]]);export{u as __pageData,m as default};
